  1→"use client";
  2→
  3→import { useEffect, useRef } from "react";
  4→import { useUndoRedo } from "./useUndoRedo";
  5→import { useFlowStore } from "@/store/useFlowStore";
  6→import type { FlowNode, FlowEdge } from "@/store/types";
  7→import { counterToId } from "@/lib/id";
  8→
  9→interface ClipboardData {
 10→  nodes: FlowNode[];
 11→  edges: FlowEdge[];
 12→}
 13→
 14→let clipboard: ClipboardData | null = null;
 15→
 16→export function useKeyboardShortcuts() {
 17→  const { undo, redo } = useUndoRedo();
 18→  const storeRef = useRef(useFlowStore);
 19→
 20→  useEffect(() => {
 21→    const handler = (e: KeyboardEvent) => {
 22→      // Skip if user is typing in an input/textarea
 23→      const tag = (e.target as HTMLElement)?.tagName;
 24→      if (tag === "INPUT" || tag === "TEXTAREA") return;
 25→
 26→      const isCtrl = e.ctrlKey || e.metaKey;
 27→
 28→      if (isCtrl && e.key === "z" && !e.shiftKey) {
 29→        e.preventDefault();
 30→        undo();
 31→      }
 32→
 33→      if (isCtrl && e.key === "z" && e.shiftKey) {
 34→        e.preventDefault();
 35→        redo();
 36→      }
 37→
 38→      if (isCtrl && e.key === "Z") {
 39→        e.preventDefault();
 40→        redo();
 41→      }
 42→
 43→      if (isCtrl && e.key === "s") {
 44→        e.preventDefault();
 45→        window.dispatchEvent(new CustomEvent("flowmaid:export"));
 46→      }
 47→
 48→      // Select all nodes and edges
 49→      if (isCtrl && e.key === "a") {
 50→        e.preventDefault();
 51→        const state = storeRef.current.getState();
 52→        storeRef.current.setState({
 53→          nodes: state.nodes.map((n) => ({ ...n, selected: true })),
 54→          edges: state.edges.map((edge) => ({ ...edge, selected: true })),
 55→        });
 56→      }
 57→
 58→      // Copy selected nodes
 59→      if (isCtrl && e.key === "c") {
 60→        const state = storeRef.current.getState();
 61→        const selectedNodes = state.nodes.filter((n) => n.selected);
 62→        if (selectedNodes.length === 0) return;
 63→        const nodeIds = new Set(selectedNodes.map((n) => n.id));
 64→        const relatedEdges = state.edges.filter(
 65→          (edge) => nodeIds.has(edge.source) && nodeIds.has(edge.target)
 66→        );
 67→        clipboard = { nodes: selectedNodes, edges: relatedEdges };
 68→      }
 69→
 70→      // Paste
 71→      if (isCtrl && e.key === "v") {
 72→        if (!clipboard || clipboard.nodes.length === 0) return;
 73→        e.preventDefault();
 74→        const state = storeRef.current.getState();
 75→        let counter = state.nextIdCounter;
 76→        const idMap = new Map<string, string>();
 77→
 78→        const newNodes: FlowNode[] = clipboard.nodes.map((n) => {
 79→          const newId = counterToId(counter++);
 80→          idMap.set(n.id, newId);
 81→          return {
 82→            ...n,
 83→            id: newId,
 84→            position: { x: n.position.x + 30, y: n.position.y + 30 },
 85→            data: { ...n.data },
 86→            selected: true,
 87→          };
 88→        });
 89→
 90→        const newEdges: FlowEdge[] = clipboard.edges.map((edge) => {
 91→          const newSource = idMap.get(edge.source) ?? edge.source;
 92→          const newTarget = idMap.get(edge.target) ?? edge.target;
 93→          return {
 94→            ...edge,
 95→            id: `${newSource}-${newTarget}-${edge.sourceHandle ?? "d"}-${edge.targetHandle ?? "d"}`,
 96→            source: newSource,
 97→            target: newTarget,
 98→            selected: false,
 99→          };
100→        });
101→
102→        // Deselect existing nodes
103→        const deselectedNodes = state.nodes.map((n) => ({ ...n, selected: false }));
104→
105→        storeRef.current.setState({
106→          nodes: [...deselectedNodes, ...newNodes],
107→          edges: [...state.edges, ...newEdges],
108→          nextIdCounter: counter,
109→        });
110→      }
111→    };
112→
113→    window.addEventListener("keydown", handler);
114→    return () => window.removeEventListener("keydown", handler);
115→  }, [undo, redo]);
116→}
