  3→import {
  4→  applyNodeChanges,
  5→  applyEdgeChanges,
  6→  MarkerType,
  7→} from "@xyflow/react";
  8→import type { FlowState, FlowNode, FlowEdge, PredictiveInputState } from "./types";
  9→import type { NodeShape, EdgeType, MarkerStyle, BorderStyle, FlowDirection, ComponentDefinition, ComponentInternalNode, ComponentInternalEdge } from "@/types/flow";
 10→import { counterToId, idToCounter } from "@/lib/id";
 11→import {
 12→  DEFAULT_NODE_WIDTH,
 13→  DEFAULT_NODE_HEIGHT,
 14→  DEFAULT_DIAMOND_SIZE,
 15→  GHOST_NODE_ID,
 16→} from "@/lib/constants";
 17→import { serialize } from "@/lib/flowmaid/serialize";
 18→import { generateComponentChildren, calculateComponentSize, rescaleComponentChildren, generateBridgeEdges, COMPONENT_HEADER_HEIGHT, COMPONENT_PADDING } from "@/lib/component-children";
 19→
 20→function markerStyleToMarker(style?: MarkerStyle, color?: string) {
 21→  switch (style) {
 22→    case "arrow":
 23→      return color ? { type: MarkerType.Arrow, color } : { type: MarkerType.Arrow };
 24→    case "arrowclosed":
 25→      return color ? { type: MarkerType.ArrowClosed, color } : { type: MarkerType.ArrowClosed };
 26→    case "none":
 27→      return undefined;
 28→    default:
 29→      return undefined;
 30→  }
 31→}
 32→
 33→function reconcileBridgeEdges(nodes: FlowNode[], edges: FlowEdge[], defs: ComponentDefinition[], direction: FlowDirection = "TD"): FlowEdge[] {
 34→  // Remove all existing bridge edges
 35→  const nonBridgeEdges = edges.filter((e) => !e.data?.isBridgeEdge);
 36→
 37→  // Generate bridge edges for all component instances
 38→  const allBridgeEdges: FlowEdge[] = [];
 39→  for (const node of nodes) {
 40→    if (node.type !== "componentInstance" || !node.data.componentDefinitionId) continue;
 41→    const def = defs.find((d) => d.id === node.data.componentDefinitionId);
 42→    if (!def) continue;
 43→
 44→    const bridges = generateBridgeEdges({
 45→      parentId: node.id,
 46→      def,
 47→      allEdges: nonBridgeEdges,
 48→      direction: def.direction ?? direction,
 49→    });
 50→
 51→    // If instance is collapsed, hide bridge edges
 52→    const isCollapsed = node.data.collapsed ?? false;
 53→    for (const b of bridges) {
 54→      if (isCollapsed) b.hidden = true;
 55→      allBridgeEdges.push(b);
 56→    }
 57→  }
 58→
 59→  return [...nonBridgeEdges, ...allBridgeEdges];
 60→}
 61→
 62→const initialState = {
 63→  nodes: [] as FlowNode[],
 64→  edges: [] as FlowEdge[],
 65→  direction: "TD" as const,
 66→  nextIdCounter: 0,
 67→  componentDefinitions: [] as ComponentDefinition[],
 68→  editingComponentId: null as string | null,
 69→  savedMainFlow: null as import("./types").SavedMainFlow | null,
 70→  predictiveInput: {
 71→    sourceNodeId: null,
 72→    direction: null,
 73→    ghostVisible: false,
 74→    candidates: [],
 75→    candidateIndex: 0,
 76→  } as PredictiveInputState,
 77→};
 78→
 79→export const useFlowStore = create<FlowState>()(
 80→  temporal(
 81→    (set, get) => ({
 82→      ...initialState,
 83→
 84→      addNode: (shape: string, position?: { x: number; y: number }) => {
 85→        const counter = get().nextIdCounter;
 86→        const id = counterToId(counter);
 87→
 88→        let width = DEFAULT_NODE_WIDTH;
 89→        let height = DEFAULT_NODE_HEIGHT;
 90→        if (shape === "diamond") {
 91→          width = DEFAULT_DIAMOND_SIZE;
 92→          height = DEFAULT_DIAMOND_SIZE;
 93→        } else if (shape === "circle") {
 94→          width = DEFAULT_NODE_HEIGHT * 2;
 95→          height = DEFAULT_NODE_HEIGHT * 2;
 96→        } else if (shape === "hexagon") {
 97→          width = DEFAULT_NODE_WIDTH + 20;
 98→          height = DEFAULT_NODE_HEIGHT + 10;
 99→        } else if (shape === "cylinder") {
100→          width = DEFAULT_NODE_WIDTH;
101→          height = DEFAULT_NODE_HEIGHT + 20;
102→        } else if (shape === "document") {
103→          width = DEFAULT_NODE_WIDTH;
104→          height = DEFAULT_NODE_HEIGHT + 10;
105→        } else if (shape === "predefinedProcess") {
106→          width = DEFAULT_NODE_WIDTH + 20;
107→          height = DEFAULT_NODE_HEIGHT;
108→        } else if (shape === "display") {
109→          width = DEFAULT_NODE_WIDTH + 20;
110→          height = DEFAULT_NODE_HEIGHT;
111→        } else if (shape === "text") {
112→          width = DEFAULT_NODE_WIDTH;
113→          height = DEFAULT_NODE_HEIGHT;
114→        }
115→
116→        const isText = shape === "text";
117→        const newNode: FlowNode = {
118→          id,
119→          type: shape,
120→          position: position ?? { x: 250, y: 150 },
121→          data: {
122→            label: isText ? "Text" : id,
123→            shape: shape as NodeShape,
124→            ...(isText && { fillOpacity: 0, borderOpacity: 0 }),
125→          },
126→          style: { width, height },
127→        };
128→
129→        set({
130→          nodes: [...get().nodes, newNode],
131→          nextIdCounter: counter + 1,
132→        });
133→      },
134→
135→      removeNodes: (ids: string[]) => {
136→        const { nodes, edges, editingComponentId } = get();
137→        // In component editing mode, protect locked (entry/exit) nodes
138→        const protectedIds = editingComponentId
139→          ? new Set(nodes.filter((n) => n.data.isLocked).map((n) => n.id))
140→          : new Set<string>();
141→        const idSet = new Set(ids.filter((id) => !protectedIds.has(id)));
142→        if (idSet.size === 0) return;
143→        // Also remove children of component instances being deleted
144→        for (const n of nodes) {
145→          if (n.data.componentParentId && idSet.has(n.data.componentParentId as string)) {
146→            idSet.add(n.id);
147→          }
148→        }
149→        set({
150→          nodes: nodes.filter((n) => !idSet.has(n.id)),
151→          edges: edges.filter(
152→            (e) => !idSet.has(e.source) && !idSet.has(e.target)
153→          ),
154→        });
155→      },
156→
157→      updateNodeLabel: (id: string, label: string) => {
158→        // In component editing mode, protect locked (entry/exit) nodes
159→        const node = get().nodes.find((n) => n.id === id);
160→        if (node?.data.isLocked && get().editingComponentId) return;
161→        set({
162→          nodes: get().nodes.map((n) => {
163→            if (n.id !== id) return n;
164→            const updated = { ...n, data: { ...n.data, label } };
165→            // Auto-expand height for multiline text
166→            const lineCount = label.split("\n").length;
167→            if (lineCount > 1) {
168→              const fontSize = n.data.fontSize ?? 14;
169→              const lineHeight = fontSize * 1.5;
170→              const padding = 20; // vertical padding
171→              const minHeight = padding + lineCount * lineHeight;
172→              const currentH = (n.style as Record<string, number>)?.height ?? DEFAULT_NODE_HEIGHT;
173→              if (minHeight > currentH) {
174→                updated.style = { ...n.style, height: Math.round(minHeight) };
175→              }
176→            }
177→            return updated;
178→          }),
179→        });
180→      },
181→
182→      updateNodeId: (oldId: string, newId: string) => {
183→        const { nodes, edges } = get();
184→        if (oldId === newId) return true;
185→        if (nodes.some((n) => n.id === newId)) return false;
186→
187→        set({
188→          nodes: nodes.map((n) =>
189→            n.id === oldId ? { ...n, id: newId } : n
190→          ),
191→          edges: edges.map((e) => ({
192→            ...e,
193→            id:
194→              e.source === oldId || e.target === oldId
195→                ? `${e.source === oldId ? newId : e.source}-${e.target === oldId ? newId : e.target}`
196→                : e.id,
197→            source: e.source === oldId ? newId : e.source,
198→            target: e.target === oldId ? newId : e.target,
199→          })),
200→        });

200→        });
201→        return true;
202→      },
203→
204→      updateNodeColors: (id: string, fillColor?: string | null, borderColor?: string | null) => {
205→        set({
206→          nodes: get().nodes.map((n) => {
207→            if (n.id !== id) return n;
208→            const newData = { ...n.data };
209→            if (fillColor !== undefined) newData.fillColor = fillColor ?? undefined;
210→            if (borderColor !== undefined) newData.borderColor = borderColor ?? undefined;
211→            return { ...n, data: newData };
212→          }),
213→        });
214→      },
215→
216→      updateNodeBorder: (id: string, borderWidth?: number, borderStyle?: BorderStyle) => {
217→        set({
218→          nodes: get().nodes.map((n) => {
219→            if (n.id !== id) return n;
220→            const newData = { ...n.data };
221→            if (borderWidth !== undefined) newData.borderWidth = borderWidth;
222→            if (borderStyle !== undefined) newData.borderStyle = borderStyle;
223→            return { ...n, data: newData };
224→          }),
225→        });
226→      },
227→
228→      updateNodeTextStyle: (id, style) => {
229→        set({
230→          nodes: get().nodes.map((n) => {
231→            if (n.id !== id) return n;
232→            const newData = { ...n.data };
233→            if (style.fontSize !== undefined) newData.fontSize = style.fontSize;
234→            if (style.textColor !== undefined) newData.textColor = style.textColor || undefined;
235→            if (style.textAlign !== undefined) newData.textAlign = style.textAlign;
236→            if (style.textVerticalAlign !== undefined) newData.textVerticalAlign = style.textVerticalAlign;
237→            if (style.bold !== undefined) newData.bold = style.bold;
238→            if (style.italic !== undefined) newData.italic = style.italic;
239→            if (style.underline !== undefined) newData.underline = style.underline;
240→            return { ...n, data: newData };
241→          }),
242→        });
243→      },
244→
245→      updateNodeColorAdjust: (id, target, opacity, lightness) => {
246→        set({
247→          nodes: get().nodes.map((n) => {
248→            if (n.id !== id) return n;
