371→        if (!def) return;
372→
373→        // Remove old children and internal edges
374→        const oldChildIds = new Set(
375→          get().nodes.filter((n) => n.data.componentParentId === nodeId).map((n) => n.id)
376→        );
377→        const filteredNodes = get().nodes.filter((n) => !oldChildIds.has(n.id));
