413→      toggleComponentCollapse: (nodeId: string) => {
414→        const node = get().nodes.find((n) => n.id === nodeId);
415→        if (!node) return;
416→        const newCollapsed = !node.data.collapsed;
417→
418→        // Collect child IDs for edge filtering
419→        const childIds = new Set(
420→          get().nodes.filter((n) => n.data.componentParentId === nodeId).map((n) => n.id)
421→        );
422→
423→        // Calculate z-index for expanded component (parent: maxZ+1, children: maxZ+2)
424→        const allZ = get().nodes.map((nd) => nd.zIndex ?? 0);
425→        const maxZ = allZ.length > 0 ? Math.max(...allZ) : 0;
426→
427→        const updatedNodes = get().nodes.map((n) => {
428→          if (n.id === nodeId) {
429→            if (newCollapsed) {
430→              // Save expanded size and restore collapsed size (or default 150x50)
431→              const currentW = n.width ?? (n.style as Record<string, unknown>)?.width as number | undefined;
432→              const currentH = n.height ?? (n.style as Record<string, unknown>)?.height as number | undefined;
433→              const collapsedSize = n.data.collapsedSize ?? { width: 150, height: 50 };
434→              // Restore z-index from before expand
435→              const restoredZ = n.data.preExpandZIndex ?? (n.zIndex ?? 0);
436→              return {
437→                ...n,
438→                width: collapsedSize.width,
439→                height: collapsedSize.height,
440→                zIndex: restoredZ,
441→                data: {
442→                  ...n.data,
443→                  collapsed: true,
444→                  expandedSize: currentW && currentH ? { width: currentW, height: currentH } : undefined,
445→                  preExpandZIndex: undefined,
446→                },
447→                style: { width: collapsedSize.width, height: collapsedSize.height },
448→              };
449→            } else {
450→              // Save collapsed size and restore expanded size
451→              const currentW = n.width ?? (n.style as Record<string, unknown>)?.width as number | undefined;
452→              const currentH = n.height ?? (n.style as Record<string, unknown>)?.height as number | undefined;
453→              const def = get().componentDefinitions.find((d) => d.id === n.data.componentDefinitionId);
