457→              return {
458→                ...n,
459→                width: expandedSize.width,
460→                height: expandedSize.height,
461→                zIndex: maxZ + 1,
462→                data: {
463→                  ...n.data,
464→                  collapsed: false,
465→                  collapsedSize: currentW && currentH ? { width: currentW, height: currentH } : undefined,
466→                  preExpandZIndex: preExpandZ,
467→                },
468→                style: { width: expandedSize.width, height: expandedSize.height },
469→              };
470→            }
471→          }
472→          // Hide/show child nodes and set z-index above parent
473→          if (n.data.componentParentId === nodeId) {
474→            if (newCollapsed) {
475→              return { ...n, hidden: true };
476→            }
477→            return { ...n, hidden: false, zIndex: maxZ + 2 };
478→          }
479→          return n;
480→        });
