138→function SubMenu({ label, children }: { label: string; children: React.ReactNode }) {
139→  const [open, setOpen] = useState(false);
140→  const subRef = useRef<HTMLDivElement>(null);
141→  const [pos, setPos] = useState<{ left?: string; right?: string; top: string }>({ top: "0" });
142→
143→  useEffect(() => {
144→    if (!open || !subRef.current) return;
145→    const rect = subRef.current.getBoundingClientRect();
146→    const vw = window.innerWidth;
147→    const vh = window.innerHeight;
148→    const newPos: { left?: string; right?: string; top: string } = { top: "0" };
149→    // Flip to left if overflowing right
150→    if (rect.right > vw) {
151→      newPos.right = "100%";
152→    } else {
153→      newPos.left = "100%";
154→    }
155→    // Shift up if overflowing bottom
156→    if (rect.bottom > vh) {
157→      newPos.top = `${vh - rect.bottom}px`;
158→    }
159→    setPos(newPos);
160→  }, [open]);
161→
162→  return (
