const handler = (e: KeyboardEvent) => {
  // INPUT/TEXTAREA フォーカス中はスキップ
  const tag = (e.target as HTMLElement)?.tagName;
  if (tag === "INPUT" || tag === "TEXTAREA") return;

  const isCtrl = e.ctrlKey || e.metaKey;

  // Ctrl+Z → undo
  if (isCtrl && e.key === "z" && !e.shiftKey) {
    e.preventDefault();
    undo();
