export const locales = {
  en: {
    // Toolbar
    addNode: "Add node",
    // Context menu
    changeShape: "Change Shape",
    fillColor: "Fill Color",
    borderColor: "Border Color",
    // ... (カテゴリ別に組織化)
  }
}
```

#### 4. キーボードショートカットパターン（useKeyboardShortcuts.ts L20-46）

```typescript
const handler = (e: KeyboardEvent) => {
  // INPUT/TEXTAREA フォーカス中はスキップ
  const tag = (e.target as HTMLElement)?.tagName;
  if (tag === "INPUT" || tag === "TEXTAREA") return;

  const isCtrl = e.ctrlKey || e.metaKey;

  // Ctrl+Z → undo
  if (isCtrl && e.key === "z" && !e.shiftKey) {
    e.preventDefault();
    undo();
  }
  // ... (他のショートカット)
};

window.addEventListener("keydown", handler);
```

#### 5. Store action パターン（useFlowStore.ts）

```typescript
updateNodeColors: (id: string, fillColor?: string | null, borderColor?: string | null) => {
  set({
    nodes: get().nodes.map((n) => {
      if (n.id !== id) return n;
      const newData = { ...n.data };
      if (fillColor !== undefined) newData.fillColor = fillColor ?? undefined;
      if (borderColor !== undefined) newData.borderColor = borderColor ?? undefined;
      return { ...n, data: newData };
    }),
  });
};

updateNodeBorder: (id: string, borderWidth?: number, borderStyle?: BorderStyle) => { /* ... */ };
updateNodeTextStyle: (id, style) => { /* ... */ };
// など
```

#### 6. CSS グローバル定義（globals.css）

- L51-57: `@keyframes shake`
- L134-415: テーマカラー、ダークモード対応
- L451-481: `.ctx-menu`, `.ctx-item` スタイル

新しい `@keyframes` は **L57 の `shake` keyframes 直後（L58-90 付近）** に追加可能。

---

### 実装上の重要ポイント

1. **マウス位置追跡**: R キー押下時に現在のマウス位置を取得する必要がある
   - `useKeyboardShortcuts.ts` では `e` オブジェクトのみで、座標はない
   - 別途 `mousemove` リスナーで `mousePos` を管理する必要あり

2. **i18n キーの命名規則**: パイメニューのラベルに対応する翻訳キーを `locales.ts` に追加
   - 例: `pieMenuColor`, `pieMenuOrder`, `pieMenuAlign` など

3. **Store action との連携**: FormatBar と同じ action を呼び出す
   - `updateNodeColors()`, `updateNodeBorder()`, `updateNodeTextStyle()` など既存を再利用
   - 新しい action は不要（仕様書も既存 action に基づいて設計済み）

4. **パフォーマンス最適化**: ノードホバーやドラッグ中の再レンダリング対策
   - パイメニュー表示中は ReactFlow のパン/ズーム抑制が必要
   - メモリ化された候補データ構造（仕様書 `pieMenuData.ts` 参照）

5. **CSS アニメーション**: 仕様書で定義済み
   - `FADE_MS: 140ms`（階層切り替え）
   - `popIn: 140ms ease-out` + `18ms stagger`（ラベル出現）
   - グローバル CSS に `@keyframes` を追加

---

### 選択状態の取得方法

```typescript
// FlowCanvas.tsx で既に使用されているパターン
const nodes = useFlowStore((s) => s.nodes);
const edges = useFlowStore((s) => s.edges);

// 選択状態のフィルター
const selectedNodeIds = nodes.filter(n => n.selected).map(n => n.id);
const selectedEdgeIds = edges.filter(e => e.selected).map(e => e.id);
```

---

### フォーマットバーとの構造比較

FormatBar (L1-400+) の実装:
- `ColorDropdown` コンポーネント: 色パレット + 透明度/明暗スライダー
- `ColorSwatch`: 色見本表示
- `COLORS`, `BORDER_WIDTHS`, `FONT_SIZES` 配列: 選択肢定義

パイメニュー実装時は以下を参考にする:
- 色リング 2D 制御（明暗 = 半径、透明度 = 角度）の計算ロジック
- Store action 呼び出しのパターン

---

### 仕様書との対応

パイメニュー仕様書 (`specs/pie-menu.md`) は以下を完全定義:
- **Section 4-5**: NODE_MENU / EDGE_MENU データ構造
- **Section 6**: `PieMenuItem` インターフェース
- **Section 8**: zustand store 接続方針（既存 action のマッピング表あり）

実装時は `src/lib/pieMenuData.ts` に仕様書の "Section 4-5" をそのまま翻訳すればよい。

