import type React from "react";

// ── Action types (discriminated union) ──────────────────────
export type PieMenuAction =
  | { type: "nodeFillColor"; color: string }
  | { type: "nodeBorderColor"; color: string }
  | { type: "nodeTextColor"; color: string }
  | { type: "nodeBorderWidth"; width: 1 | 2 | 4 }
  | { type: "nodeBorderStyle"; style: "solid" | "dashed" | "dotted" }
  | { type: "nodeOrder"; order: "front" | "back" | "forward" | "backward" }
  | { type: "nodeAlign"; alignment: "left" | "center" | "right" | "top" | "middle" | "bottom" }
  | { type: "nodeDistribute"; axis: "horizontal" | "vertical" }
  | { type: "nodeFontSize"; size: number }
  | { type: "nodeBold" }
  | { type: "nodeItalic" }
  | { type: "nodeUnderline" }
  | { type: "nodeTextAlign"; align: "left" | "center" | "right" }
  | { type: "nodeTextVerticalAlign"; align: "top" | "middle" | "bottom" }
  | { type: "edgeLineType"; edgeType: "bezier" | "straight" | "step" }
  | { type: "edgeMarkerEnd"; marker: "arrowclosed" | "arrow" | "none" }
  | { type: "edgeMarkerStart"; marker: "arrowclosed" | "arrow" | "none" }
  | { type: "edgeStrokeWidth"; width: number }
  | { type: "edgeStrokeStyle"; style: "solid" | "dashed" | "dotted" }
  | { type: "edgeColor"; color: string };

// ── Menu item interface ─────────────────────────────────────
export interface PieMenuItem {
  id: string;
  labelKey: string;
  icon?: string;
  color: string;
  children?: PieMenuItem[];
  isColor?: boolean;
  angleOffset?: number;
  fontSize?: number;
  labelStyle?: React.CSSProperties;
  alignType?: string;
  action?: PieMenuAction;
}

// ── Color palettes ──────────────────────────────────────────
const FILL_COLORS: PieMenuItem[] = [
  { id: "fill-default", labelKey: "colorDefault", color: "#888", action: { type: "nodeFillColor", color: "" } },
  { id: "fill-red", labelKey: "colorRed", color: "#ef4444", action: { type: "nodeFillColor", color: "#ef4444" } },
  { id: "fill-orange", labelKey: "colorOrange", color: "#f97316", action: { type: "nodeFillColor", color: "#f97316" } },
  { id: "fill-yellow", labelKey: "colorYellow", color: "#eab308", action: { type: "nodeFillColor", color: "#eab308" } },
  { id: "fill-green", labelKey: "colorGreen", color: "#22c55e", action: { type: "nodeFillColor", color: "#22c55e" } },
  { id: "fill-blue", labelKey: "colorBlue", color: "#3b82f6", action: { type: "nodeFillColor", color: "#3b82f6" } },
  { id: "fill-purple", labelKey: "colorPurple", color: "#a855f7", action: { type: "nodeFillColor", color: "#a855f7" } },
  { id: "fill-pink", labelKey: "colorPink", color: "#ec4899", action: { type: "nodeFillColor", color: "#ec4899" } },
];

const BORDER_COLORS: PieMenuItem[] = [
  { id: "bc-default", labelKey: "colorDefault", color: "#888", action: { type: "nodeBorderColor", color: "" } },
  { id: "bc-red", labelKey: "colorRed", color: "#ef4444", action: { type: "nodeBorderColor", color: "#ef4444" } },
  { id: "bc-orange", labelKey: "colorOrange", color: "#f97316", action: { type: "nodeBorderColor", color: "#f97316" } },
  { id: "bc-green", labelKey: "colorGreen", color: "#22c55e", action: { type: "nodeBorderColor", color: "#22c55e" } },
  { id: "bc-blue", labelKey: "colorBlue", color: "#3b82f6", action: { type: "nodeBorderColor", color: "#3b82f6" } },
  { id: "bc-purple", labelKey: "colorPurple", color: "#a855f7", action: { type: "nodeBorderColor", color: "#a855f7" } },
];

const TEXT_COLORS: PieMenuItem[] = [
  { id: "tc-default", labelKey: "colorDefault", color: "#888", action: { type: "nodeTextColor", color: "" } },
  { id: "tc-red", labelKey: "colorRed", color: "#ef4444", action: { type: "nodeTextColor", color: "#ef4444" } },
  { id: "tc-blue", labelKey: "colorBlue", color: "#3b82f6", action: { type: "nodeTextColor", color: "#3b82f6" } },
  { id: "tc-white", labelKey: "colorWhite", color: "#e2e8f0", action: { type: "nodeTextColor", color: "#e2e8f0" } },
  { id: "tc-black", labelKey: "colorBlack", color: "#334155", action: { type: "nodeTextColor", color: "#334155" } },
];

const EDGE_COLORS: PieMenuItem[] = [
  { id: "ec-default", labelKey: "colorDefault", color: "#888", action: { type: "edgeColor", color: "" } },
  { id: "ec-red", labelKey: "colorRed", color: "#ef4444", action: { type: "edgeColor", color: "#ef4444" } },
  { id: "ec-orange", labelKey: "colorOrange", color: "#f97316", action: { type: "edgeColor", color: "#f97316" } },
  { id: "ec-yellow", labelKey: "colorYellow", color: "#eab308", action: { type: "edgeColor", color: "#eab308" } },
  { id: "ec-green", labelKey: "colorGreen", color: "#22c55e", action: { type: "edgeColor", color: "#22c55e" } },
  { id: "ec-blue", labelKey: "colorBlue", color: "#3b82f6", action: { type: "edgeColor", color: "#3b82f6" } },
  { id: "ec-purple", labelKey: "colorPurple", color: "#a855f7", action: { type: "edgeColor", color: "#a855f7" } },
  { id: "ec-pink", labelKey: "colorPink", color: "#ec4899", action: { type: "edgeColor", color: "#ec4899" } },
];

// ── NODE_MENU ───────────────────────────────────────────────
export const NODE_MENU: PieMenuItem[] = [
  // 0: → right — Color
  {
    id: "node-color",
    labelKey: "pieColor",
    icon: "🎨",
    color: "#f472b6",
    children: [
      { id: "node-fill", labelKey: "pieFill", icon: "◼", color: "#f472b6", isColor: true, children: FILL_COLORS },
      { id: "node-border-color", labelKey: "pieBorderColor", icon: "▢", color: "#fb923c", isColor: true, children: BORDER_COLORS },
