      { id: "order-back", labelKey: "sendToBack", color: "#a78bfa", action: { type: "nodeOrder", order: "back" } },
      { id: "order-backward", labelKey: "sendBackward", color: "#c084fc", action: { type: "nodeOrder", order: "backward" } },
      { id: "order-forward", labelKey: "bringForward", color: "#e879f9", action: { type: "nodeOrder", order: "forward" } },
      { id: "order-front", labelKey: "bringToFront", color: "#f472b6", action: { type: "nodeOrder", order: "front" } },
    ],
  },
  // 2: ↙ left-bottom — Align
  {
    id: "node-align",
