        icon: "✛",
        color: "#38bdf8",
        angleOffset: -90,
        children: [
          { id: "align-vmiddle", labelKey: "alignMiddle", color: "#7dd3fc", alignType: "vmiddle", action: { type: "nodeAlign", alignment: "middle" } },
          { id: "align-vtop", labelKey: "alignTop", color: "#67e8f9", alignType: "vtop", action: { type: "nodeAlign", alignment: "top" } },
          { id: "align-hright", labelKey: "alignRight", color: "#22d3ee", alignType: "hright", action: { type: "nodeAlign", alignment: "right" } },
          { id: "align-hcenter", labelKey: "alignCenter", color: "#2dd4bf", alignType: "hcenter", action: { type: "nodeAlign", alignment: "center" } },
          { id: "align-hleft", labelKey: "alignLeft", color: "#34d399", alignType: "hleft", action: { type: "nodeAlign", alignment: "left" } },
          { id: "align-vbottom", labelKey: "alignBottom", color: "#4ade80", alignType: "vbottom", action: { type: "nodeAlign", alignment: "bottom" } },
        ],
      },
      {
        id: "align-dist",
