// ── Action types (discriminated union) ──────────────────────
export type PieMenuAction =
  | { type: "nodeFillColor"; color: string }
  | { type: "nodeBorderColor"; color: string }
  | { type: "nodeTextColor"; color: string }
  | { type: "nodeBorderWidth"; width: 1 | 2 | 4 }
  | { type: "nodeBorderStyle"; style: "solid" | "dashed" | "dotted" }
  | { type: "nodeOrder"; order: "front" | "back" | "forward" | "backward" }
  | { type: "nodeAlign"; alignment: "left" | "center" | "right" | "top" | "middle" | "bottom" }
  | { type: "nodeDistribute"; axis: "horizontal" | "vertical" }
  | { type: "nodeFontSize"; size: number }
  | { type: "nodeBold" }
  | { type: "nodeItalic" }
  | { type: "nodeUnderline" }
  | { type: "nodeTextAlign"; align: "left" | "center" | "right" }
  | { type: "nodeTextVerticalAlign"; align: "top" | "middle" | "bottom" }
  | { type: "edgeLineType"; edgeType: "bezier" | "straight" | "step" }
  | { type: "edgeMarkerEnd"; marker: "arrowclosed" | "arrow" | "none" }
  | { type: "edgeMarkerStart"; marker: "arrowclosed" | "arrow" | "none" }
  | { type: "edgeStrokeWidth"; width: number }
  | { type: "edgeStrokeStyle"; style: "solid" | "dashed" | "dotted" }
  | { type: "edgeColor"; color: string };

