246→        if (e.ctrlKey || e.metaKey || e.altKey) return;
247→        e.preventDefault();
248→        const s = stateRef.current;
249→        if (s.isOpen) {
250→          setState(INITIAL_STATE);
251→        } else {
252→          setState({
253→            ...INITIAL_STATE,
254→            isOpen: true,
255→            position: { ...mousePosRef.current },
256→          });
257→        }
258→      }
259→    };
260→
261→    const onContextMenu = (e: MouseEvent) => {
262→      if (stateRef.current.isOpen) {
263→        e.preventDefault();
264→        setState(INITIAL_STATE);
265→      }
266→    };
267→
268→    window.addEventListener("mousemove", onMouseMove);
269→    window.addEventListener("keydown", onKeyDown);
270→    window.addEventListener("contextmenu", onContextMenu, true);
271→
272→    return () => {
273→      window.removeEventListener("mousemove", onMouseMove);
274→      window.removeEventListener("keydown", onKeyDown);
275→      window.removeEventListener("contextmenu", onContextMenu, true);
276→    };
277→  }, []);
278→
279→  return {
280→    state,
281→    setState,
282→    rootMenu,
283→    currentItems,
284→    currentAngleOffset,
285→    selectedNodeIds,
286→    selectedEdgeIds,
287→    open,
288→    close,
289→    drillDown,
290→    drillUp,
291→    dispatchAction,
292→    getBreadcrumb: (t: (k: TranslationKey) => string) => rootMenu ? getBreadcrumb(rootMenu, state.path, t) : "",
293→  };
294→}
