 17→// ── Constants ───────────────────────────────────────────────
 18→const CLOSE_R = LABEL_R + 60;
 19→const INDICATOR_WIDTH_DEG = 6;
 20→const STAGGER_MS = 18;
 21→const POP_IN_MS = 140;
 22→const SVG_SIZE = (CLOSE_R + 20) * 2;
 23→const HALF = SVG_SIZE / 2;
