 25→// ── Geometry helpers ────────────────────────────────────────
 26→const deg2rad = (d: number) => (d * Math.PI) / 180;
 27→
 28→function describeDonutSegment(
 29→  cx: number, cy: number,
 30→  innerR: number, outerR: number,
 31→  startDeg: number, endDeg: number,
 32→): string {
 33→  const s1 = deg2rad(startDeg);
 34→  const e1 = deg2rad(endDeg);
 35→  const sweep = endDeg - startDeg;
 36→  const large = sweep > 180 ? 1 : 0;
 37→
 38→  const ox1 = cx + outerR * Math.cos(s1);
 39→  const oy1 = cy + outerR * Math.sin(s1);
 40→  const ox2 = cx + outerR * Math.cos(e1);
 41→  const oy2 = cy + outerR * Math.sin(e1);
 42→  const ix1 = cx + innerR * Math.cos(e1);
 43→  const iy1 = cy + innerR * Math.sin(e1);
 44→  const ix2 = cx + innerR * Math.cos(s1);
 45→  const iy2 = cy + innerR * Math.sin(s1);
 46→
 47→  return [
 48→    `M ${ox1} ${oy1}`,
 49→    `A ${outerR} ${outerR} 0 ${large} 1 ${ox2} ${oy2}`,
 50→    `L ${ix1} ${iy1}`,
 51→    `A ${innerR} ${innerR} 0 ${large} 0 ${ix2} ${iy2}`,
 52→    "Z",
 53→  ].join(" ");
 54→}
 55→
 56→function hitTest(angle: number, r: number, items: PieMenuItem[], angleOffset: number): number {
 57→  if (r < DEADZONE) return -2; // deadzone
 58→  if (r > CLOSE_R) return -3;  // far away
 59→  if (items.length === 0) return -1;
 60→
 61→  const angles = getSegmentAngles(items.length, angleOffset);
 62→  for (let i = 0; i < angles.length; i++) {
 63→    let { start, end } = angles[i];
 64→    // Normalize to 0-360
 65→    start = ((start % 360) + 360) % 360;
 66→    end = ((end % 360) + 360) % 360;
 67→
 68→    let inRange: boolean;
 69→    if (start <= end) {
 70→      inRange = angle >= start && angle <= end;
 71→    } else {
 72→      // Wraps around 0°
 73→      inRange = angle >= start || angle <= end;
 74→    }
 75→    if (inRange && r >= RING_INNER - 10 && r <= CLOSE_R) return i;
 76→  }
 77→  return -1;
 78→}
