188→    }
189→    if (hoveredIndex === -3 || hoveredIndex === -1) {
190→      // Far away or no segment → close
191→      onClose();
192→      return;
193→    }
194→
195→    const item = items[hoveredIndex];
196→    if (!item) return;
197→
198→    if (item.children && item.children.length > 0) {
199→      onDrillDown(hoveredIndex);
200→    } else if (item.action) {
201→      onDispatch(item.action);
