253→            <>
254→              <circle cx={HALF} cy={HALF} r={RING_OUTER} fill="#ffffff08" stroke="#ffffff15" strokeWidth={1} />
255→              <text
256→                x={HALF}
257→                y={HALF}
258→                textAnchor="middle"
259→                dominantBaseline="central"
260→                fill="#ffffff55"
261→                fontSize={13}
262→                fontFamily="system-ui, sans-serif"
