267→          ) : (
268→            <>
269→              {/* Segments */}
270→              {segments.map((seg, i) => {
271→                const item = items[i];
272→                const isHovered = hoveredIndex === i;
273→                const fillColor = isHovered ? `${item.color}30` : "#ffffff05";
274→                const strokeColor = isHovered ? `${item.color}55` : "#ffffff08";
275→
276→                return (
277→                  <path
278→                    key={item.id}
279→                    d={describeDonutSegment(HALF, HALF, RING_INNER, RING_OUTER, seg.start, seg.end)}
280→                    fill={fillColor}
281→                    stroke={strokeColor}
282→                    strokeWidth={1}
