288→              {/* Cursor indicator arc */}
289→              {state.mouseR >= RING_INNER && hoveredIndex >= 0 && (
290→                <path
291→                  d={describeDonutSegment(
292→                    HALF, HALF,
293→                    RING_OUTER - 2, RING_OUTER + 4,
294→                    state.mouseAngle - INDICATOR_WIDTH_DEG / 2,
295→                    state.mouseAngle + INDICATOR_WIDTH_DEG / 2,
296→                  )}
297→                  fill={items[hoveredIndex]?.color ?? "#8b5cf6"}
298→                  filter="url(#pie-glow)"
299→                  opacity={0.9}
300→                />
301→              )}
302→
303→              {/* Labels */}
304→              {segments.map((seg, i) => {
305→                const item = items[i];
306→                const isHovered = hoveredIndex === i;
307→                const labelX = HALF + LABEL_R * Math.cos(deg2rad(seg.center));
308→                const labelY = HALF + LABEL_R * Math.sin(deg2rad(seg.center));
309→
310→                const displayLabel = t(item.labelKey as TranslationKey);
311→                const icon = item.icon ?? "";
312→
313→                // Determine label content
