 26→// ── Layout constants ────────────────────────────────────────
 27→export const DEADZONE = 28;
 28→export const RING_INNER = 48;
 29→export const RING_OUTER = 88;
 30→export const LABEL_R = 128;
 31→export const GAP_DEG = 1.2;
 32→export const FADE_MS = 140;
 33→const CLOSE_R = LABEL_R + 60;
