 35→// ── Selectors (stable references) ───────────────────────────
 36→const selectSelectedNodeIds = (s: { nodes: { id: string; selected?: boolean }[] }) =>
 37→  s.nodes.filter((n) => n.selected).map((n) => n.id).join(",");
 38→const selectSelectedEdgeIds = (s: { edges: { id: string; selected?: boolean; data?: { isBridgeEdge?: boolean } }[] }) =>
 39→  s.edges.filter((e) => e.selected && !e.data?.isBridgeEdge).map((e) => e.id).join(",");
