 41→// ── Geometry helpers ────────────────────────────────────────
 42→export function getSegmentAngles(count: number, angleOffset = 0) {
 43→  const sliceDeg = 360 / count;
 44→  return Array.from({ length: count }, (_, i) => {
 45→    const center = angleOffset + i * sliceDeg;
 46→    const half = sliceDeg / 2 - GAP_DEG / 2;
 47→    return { start: center - half, center, end: center + half };
 48→  });
 49→}
