        nodeIds.forEach((id) => {
          const node = store.nodes.find((n) => n.id === id);
          store.updateNodeTextStyle(id, { italic: !node?.data?.italic });
        });
        break;
      case "nodeUnderline":
        nodeIds.forEach((id) => {
          const node = store.nodes.find((n) => n.id === id);
