"use client";

import React, { useMemo } from "react";
import { useLocale } from "@/lib/i18n/useLocale";
import type { TranslationKey } from "@/lib/i18n/locales";
import {
  type PieMenuState,
  DEADZONE,
  RING_INNER,
  RING_OUTER,
  LABEL_R,
  GAP_DEG,
  getSegmentAngles,
} from "@/hooks/usePieMenu";
import type { PieMenuItem } from "@/lib/pieMenuData";

// ── Constants ───────────────────────────────────────────────
const CLOSE_R = LABEL_R + 60;
const INDICATOR_WIDTH_DEG = 6;
const STAGGER_MS = 18;
const POP_IN_MS = 140;
const SVG_SIZE = (CLOSE_R + 20) * 2;
const HALF = SVG_SIZE / 2;

// ── Geometry helpers ────────────────────────────────────────
const deg2rad = (d: number) => (d * Math.PI) / 180;

function describeDonutSegment(
  cx: number, cy: number,
  innerR: number, outerR: number,
  startDeg: number, endDeg: number,
): string {
  const s1 = deg2rad(startDeg);
  const e1 = deg2rad(endDeg);
  const sweep = endDeg - startDeg;
  const large = sweep > 180 ? 1 : 0;

  const ox1 = cx + outerR * Math.cos(s1);
  const oy1 = cy + outerR * Math.sin(s1);
  const ox2 = cx + outerR * Math.cos(e1);
  const oy2 = cy + outerR * Math.sin(e1);
  const ix1 = cx + innerR * Math.cos(e1);
  const iy1 = cy + innerR * Math.sin(e1);
  const ix2 = cx + innerR * Math.cos(s1);
  const iy2 = cy + innerR * Math.sin(s1);

  return [
    `M ${ox1} ${oy1}`,
    `A ${outerR} ${outerR} 0 ${large} 1 ${ox2} ${oy2}`,
    `L ${ix1} ${iy1}`,
    `A ${innerR} ${innerR} 0 ${large} 0 ${ix2} ${iy2}`,
    "Z",
  ].join(" ");
}

function hitTest(angle: number, r: number, items: PieMenuItem[], angleOffset: number): number {
  if (r < DEADZONE) return -2; // deadzone
  if (r > CLOSE_R) return -3;  // far away
  if (items.length === 0) return -1;

  const angles = getSegmentAngles(items.length, angleOffset);
  for (let i = 0; i < angles.length; i++) {
    let { start, end } = angles[i];
    // Normalize to 0-360
    start = ((start % 360) + 360) % 360;
    end = ((end % 360) + 360) % 360;

    let inRange: boolean;
    if (start <= end) {
      inRange = angle >= start && angle <= end;
    } else {
      // Wraps around 0°
      inRange = angle >= start || angle <= end;
    }
    if (inRange && r >= RING_INNER - 10 && r <= CLOSE_R) return i;
  }
  return -1;
}

// ── AlignIcon SVG helper ────────────────────────────────────
function AlignIcon({ type, size = 16 }: { type: string; size?: number }) {
  const s = size;
  const m = s / 2;
  const p = 2;

  switch (type) {
    case "hleft":
      return (
        <svg width={s} height={s} viewBox={`0 0 ${s} ${s}`}>
          <line x1={p} y1={p} x2={p} y2={s - p} stroke="currentColor" strokeWidth={1.5} />
          <rect x={p + 2} y={p + 1} width={s * 0.6} height={3} rx={1} fill="currentColor" />
          <rect x={p + 2} y={m - 1} width={s * 0.4} height={3} rx={1} fill="currentColor" />
          <rect x={p + 2} y={s - p - 4} width={s * 0.7} height={3} rx={1} fill="currentColor" />
        </svg>
      );
    case "hcenter":
      return (
        <svg width={s} height={s} viewBox={`0 0 ${s} ${s}`}>
          <line x1={m} y1={p} x2={m} y2={s - p} stroke="currentColor" strokeWidth={1} strokeDasharray="2 2" />
          <rect x={m - s * 0.3} y={p + 1} width={s * 0.6} height={3} rx={1} fill="currentColor" />
          <rect x={m - s * 0.2} y={m - 1} width={s * 0.4} height={3} rx={1} fill="currentColor" />
          <rect x={m - s * 0.35} y={s - p - 4} width={s * 0.7} height={3} rx={1} fill="currentColor" />
        </svg>
      );
    case "hright":
      return (
        <svg width={s} height={s} viewBox={`0 0 ${s} ${s}`}>
          <line x1={s - p} y1={p} x2={s - p} y2={s - p} stroke="currentColor" strokeWidth={1.5} />
          <rect x={s - p - 2 - s * 0.6} y={p + 1} width={s * 0.6} height={3} rx={1} fill="currentColor" />
          <rect x={s - p - 2 - s * 0.4} y={m - 1} width={s * 0.4} height={3} rx={1} fill="currentColor" />
          <rect x={s - p - 2 - s * 0.7} y={s - p - 4} width={s * 0.7} height={3} rx={1} fill="currentColor" />
        </svg>
      );
    case "vtop":
      return (
        <svg width={s} height={s} viewBox={`0 0 ${s} ${s}`}>
          <line x1={p} y1={p} x2={s - p} y2={p} stroke="currentColor" strokeWidth={1.5} />
          <rect x={p + 1} y={p + 2} width={4} height={s * 0.5} rx={1} fill="currentColor" />
          <rect x={m + 1} y={p + 2} width={4} height={s * 0.35} rx={1} fill="currentColor" />
        </svg>
      );
    case "vmiddle":
      return (
        <svg width={s} height={s} viewBox={`0 0 ${s} ${s}`}>
          <line x1={p} y1={m} x2={s - p} y2={m} stroke="currentColor" strokeWidth={1} strokeDasharray="2 2" />
          <rect x={p + 1} y={m - s * 0.25} width={4} height={s * 0.5} rx={1} fill="currentColor" />
          <rect x={m + 1} y={m - s * 0.175} width={4} height={s * 0.35} rx={1} fill="currentColor" />
        </svg>
      );
    case "vbottom":
      return (
        <svg width={s} height={s} viewBox={`0 0 ${s} ${s}`}>
          <line x1={p} y1={s - p} x2={s - p} y2={s - p} stroke="currentColor" strokeWidth={1.5} />
          <rect x={p + 1} y={s - p - 2 - s * 0.5} width={4} height={s * 0.5} rx={1} fill="currentColor" />
          <rect x={m + 1} y={s - p - 2 - s * 0.35} width={4} height={s * 0.35} rx={1} fill="currentColor" />
        </svg>
      );
    default:
      return null;
  }
}

// ── Props ───────────────────────────────────────────────────
interface PieMenuProps {
  state: PieMenuState;
  items: PieMenuItem[];
  angleOffset: number;
  rootMenu: PieMenuItem[] | null;
  breadcrumb: string;
  onDrillDown: (index: number) => void;
  onDrillUp: () => void;
  onDispatch: (action: NonNullable<PieMenuItem["action"]>) => void;
  onClose: () => void;
}

// ── Component ───────────────────────────────────────────────
export default function PieMenu({
  state,
  items,
  angleOffset,
  rootMenu,
  breadcrumb,
  onDrillDown,
  onDrillUp,
  onDispatch,
  onClose,
}: PieMenuProps) {
  const { t } = useLocale();

  const segments = useMemo(
    () => (items.length > 0 ? getSegmentAngles(items.length, angleOffset) : []),
    [items, angleOffset],
  );

  // Hovered index from mouse position
  const hoveredIndex = items.length > 0
    ? hitTest(state.mouseAngle, state.mouseR, items, angleOffset)
    : -1;

  const handleClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    e.preventDefault();

    if (hoveredIndex === -2) {
      // Deadzone → drill up
      onDrillUp();
      return;
    }
    if (hoveredIndex === -3 || hoveredIndex === -1) {
      // Far away or no segment → close
      onClose();
      return;
    }

    const item = items[hoveredIndex];
    if (!item) return;

    if (item.children && item.children.length > 0) {
      onDrillDown(hoveredIndex);
    } else if (item.action) {
      onDispatch(item.action);
      onClose();
    }
  };

  const noSelection = !rootMenu;

  return (
    <div
      style={{
        position: "fixed",
        inset: 0,
        zIndex: 2000,
        pointerEvents: "none",
      }}
    >
      <div
        style={{
          position: "absolute",
          left: state.position.x - HALF,
          top: state.position.y - HALF,
          width: SVG_SIZE,
          height: SVG_SIZE,
          pointerEvents: "auto",
          cursor: "default",
        }}
        onClick={handleClick}
        onContextMenu={(e) => { e.preventDefault(); onClose(); }}
      >
        <svg
          width={SVG_SIZE}
          height={SVG_SIZE}
          viewBox={`0 0 ${SVG_SIZE} ${SVG_SIZE}`}
          style={{
            overflow: "visible",
            opacity: state.isFading ? 0 : 1,
            transition: `opacity ${140}ms ease`,
          }}
        >
          {/* Filters */}
          <defs>
            <filter id="pie-glow" x="-50%" y="-50%" width="200%" height="200%">
              <feGaussianBlur stdDeviation="4" result="blur" />
              <feMerge>
                <feMergeNode in="blur" />
                <feMergeNode in="SourceGraphic" />
              </feMerge>
            </filter>
          </defs>

          {noSelection ? (
            /* Empty state */
            <>
              <circle cx={HALF} cy={HALF} r={RING_OUTER} fill="#ffffff08" stroke="#ffffff15" strokeWidth={1} />
              <text
                x={HALF}
                y={HALF}
                textAnchor="middle"
                dominantBaseline="central"
                fill="#ffffff55"
                fontSize={13}
                fontFamily="system-ui, sans-serif"
              >
                {t("pieNoSelection" as TranslationKey)}
              </text>
            </>
          ) : (
            <>
              {/* Segments */}
              {segments.map((seg, i) => {
                const item = items[i];
                const isHovered = hoveredIndex === i;
                const fillColor = isHovered ? `${item.color}30` : "#ffffff05";
                const strokeColor = isHovered ? `${item.color}55` : "#ffffff08";

                return (
                  <path
                    key={item.id}
                    d={describeDonutSegment(HALF, HALF, RING_INNER, RING_OUTER, seg.start, seg.end)}
                    fill={fillColor}
                    stroke={strokeColor}
                    strokeWidth={1}
                    style={{ transition: "fill 100ms ease, stroke 100ms ease" }}
                  />
                );
              })}

              {/* Cursor indicator arc */}
              {state.mouseR >= RING_INNER && hoveredIndex >= 0 && (
                <path
                  d={describeDonutSegment(
                    HALF, HALF,
                    RING_OUTER - 2, RING_OUTER + 4,
                    state.mouseAngle - INDICATOR_WIDTH_DEG / 2,
                    state.mouseAngle + INDICATOR_WIDTH_DEG / 2,
                  )}
                  fill={items[hoveredIndex]?.color ?? "#8b5cf6"}
                  filter="url(#pie-glow)"
                  opacity={0.9}
                />
              )}

              {/* Labels */}
              {segments.map((seg, i) => {
                const item = items[i];
                const isHovered = hoveredIndex === i;
                const labelX = HALF + LABEL_R * Math.cos(deg2rad(seg.center));
                const labelY = HALF + LABEL_R * Math.sin(deg2rad(seg.center));

                const displayLabel = t(item.labelKey as TranslationKey);
                const icon = item.icon ?? "";

                // Determine label content
                let labelContent: React.ReactNode;
                if (item.alignType) {
                  labelContent = (
                    <foreignObject
                      x={labelX - 10}
                      y={labelY - 10}
                      width={20}
                      height={20}
                      style={{ color: isHovered ? "#fff" : "#ffffff88" }}
                    >
                      <div style={{ display: "flex", alignItems: "center", justifyContent: "center", width: "100%", height: "100%" }}>
                        <AlignIcon type={item.alignType} size={16} />
                      </div>
                    </foreignObject>
                  );
                } else {
                  labelContent = null;
                }

                const textFill = isHovered ? "#fff" : "#ffffff88";
                const bgFill = "#0e0e1cdd";
                const fs = item.fontSize ?? 11;
                const textWidth = (icon ? icon.length * fs + 4 : 0) + displayLabel.length * fs * 0.6 + 16;
                const textHeight = fs + 10;

                return (
                  <g
                    key={item.id}
                    className="pie-menu-label-group"
                    style={{
                      animation: `piePopIn ${POP_IN_MS}ms ease-out ${i * STAGGER_MS}ms both`,
                    }}
                  >
                    {item.alignType ? (
                      labelContent
                    ) : (
                      <>
                        {/* Background rect */}
                        <rect
                          x={labelX - textWidth / 2}
                          y={labelY - textHeight / 2}
                          width={textWidth}
                          height={textHeight}
                          rx={4}
                          fill={bgFill}
                          stroke={isHovered ? `${item.color}55` : "transparent"}
                          strokeWidth={1}
                        />
                        {/* Color dot for color items */}
                        {item.isColor || item.action ? (
                          <circle
                            cx={labelX - textWidth / 2 + 10}
                            cy={labelY}
                            r={4}
                            fill={item.color}
                          />
                        ) : null}
                        {/* Text */}
                        <text
                          x={labelX}
                          y={labelY}
                          textAnchor="middle"
                          dominantBaseline="central"
                          fill={textFill}
                          fontSize={fs}
                          fontFamily="system-ui, sans-serif"
                          style={{
                            ...item.labelStyle,
                            transition: "fill 100ms ease",
                            transform: isHovered ? "scale(1.08)" : undefined,
                            transformOrigin: `${labelX}px ${labelY}px`,
                          }}
                        >
                          {icon ? `${icon} ` : ""}{displayLabel}
                        </text>
                      </>
                    )}
                  </g>
                );
              })}

              {/* Center deadzone */}
              <circle
                cx={HALF}
                cy={HALF}
                r={DEADZONE}
                fill="#0e0e1ccc"
                stroke="#ffffff15"
                strokeWidth={1}
              />
              {/* Breadcrumb text */}
              {breadcrumb ? (
                <text
                  x={HALF}
                  y={HALF}
                  textAnchor="middle"
                  dominantBaseline="central"
                  fill="#ffffffaa"
                  fontSize={9}
                  fontFamily="system-ui, sans-serif"
                >
                  {breadcrumb.length > 12 ? "‹" : breadcrumb || "‹"}
                </text>
              ) : (
                <text
                  x={HALF}
                  y={HALF}
                  textAnchor="middle"
                  dominantBaseline="central"
                  fill="#ffffff55"
                  fontSize={10}
                  fontFamily="system-ui, sans-serif"
                >
                  ●
                </text>
              )}
            </>
          )}
        </svg>
      </div>
    </div>
  );
}

"use client";

import React, { useMemo } from "react";
import { useLocale } from "@/lib/i18n/useLocale";
import type { TranslationKey } from "@/lib/i18n/locales";
import {
  type PieMenuState,
  DEADZONE,
  RING_INNER,
  RING_OUTER,
  LABEL_R,
  GAP_DEG,
  FADE_MS,
  getSegmentAngles,
} from "@/hooks/usePieMenu";
import type { PieMenuItem } from "@/lib/pieMenuData";

// ── Constants ───────────────────────────────────────────────
const CLOSE_R = LABEL_R + 60;
const INDICATOR_WIDTH_DEG = 6;
const STAGGER_MS = 18;
const POP_IN_MS = 140;
const SVG_SIZE = (CLOSE_R + 20) * 2;
const HALF = SVG_SIZE / 2;

// ── Geometry helpers ────────────────────────────────────────
const deg2rad = (d: number) => (d * Math.PI) / 180;

function describeDonutSegment(
  cx: number, cy: number,
  innerR: number, outerR: number,
  startDeg: number, endDeg: number,
): string {
  const s1 = deg2rad(startDeg);
  const e1 = deg2rad(endDeg);
  const sweep = endDeg - startDeg;
  const large = sweep > 180 ? 1 : 0;

  const ox1 = cx + outerR * Math.cos(s1);
  const oy1 = cy + outerR * Math.sin(s1);
  const ox2 = cx + outerR * Math.cos(e1);
  const oy2 = cy + outerR * Math.sin(e1);
  const ix1 = cx + innerR * Math.cos(e1);
  const iy1 = cy + innerR * Math.sin(e1);
  const ix2 = cx + innerR * Math.cos(s1);
  const iy2 = cy + innerR * Math.sin(s1);

  return [
    `M ${ox1} ${oy1}`,
    `A ${outerR} ${outerR} 0 ${large} 1 ${ox2} ${oy2}`,
    `L ${ix1} ${iy1}`,
    `A ${innerR} ${innerR} 0 ${large} 0 ${ix2} ${iy2}`,
    "Z",
  ].join(" ");
}

function hitTest(angle: number, r: number, items: PieMenuItem[], angleOffset: number): number {
  if (r < DEADZONE) return -2; // deadzone
  if (r > CLOSE_R) return -3;  // far away
  if (items.length === 0) return -1;

  const angles = getSegmentAngles(items.length, angleOffset);
  for (let i = 0; i < angles.length; i++) {
    let { start, end } = angles[i];
    // Normalize to 0-360
    start = ((start % 360) + 360) % 360;
    end = ((end % 360) + 360) % 360;

    let inRange: boolean;
    if (start <= end) {
      inRange = angle >= start && angle <= end;
    } else {
      // Wraps around 0°
      inRange = angle >= start || angle <= end;
    }
    if (inRange && r >= RING_INNER - 10 && r <= CLOSE_R) return i;
  }
  return -1;
}

// ── AlignIcon SVG helper ────────────────────────────────────
function AlignIcon({ type, size = 16 }: { type: string; size?: number }) {
  const s = size;
  const m = s / 2;
  const p = 2;

  switch (type) {
    case "hleft":
      return (
        <svg width={s} height={s} viewBox={`0 0 ${s} ${s}`}>
          <line x1={p} y1={p} x2={p} y2={s - p} stroke="currentColor" strokeWidth={1.5} />
          <rect x={p + 2} y={p + 1} width={s * 0.6} height={3} rx={1} fill="currentColor" />
          <rect x={p + 2} y={m - 1} width={s * 0.4} height={3} rx={1} fill="currentColor" />
          <rect x={p + 2} y={s - p - 4} width={s * 0.7} height={3} rx={1} fill="currentColor" />
        </svg>
      );
    case "hcenter":
      return (
        <svg width={s} height={s} viewBox={`0 0 ${s} ${s}`}>
          <line x1={m} y1={p} x2={m} y2={s - p} stroke="currentColor" strokeWidth={1} strokeDasharray="2 2" />
          <rect x={m - s * 0.3} y={p + 1} width={s * 0.6} height={3} rx={1} fill="currentColor" />
          <rect x={m - s * 0.2} y={m - 1} width={s * 0.4} height={3} rx={1} fill="currentColor" />
          <rect x={m - s * 0.35} y={s - p - 4} width={s * 0.7} height={3} rx={1} fill="currentColor" />
        </svg>
      );
    case "hright":
      return (
        <svg width={s} height={s} viewBox={`0 0 ${s} ${s}`}>
          <line x1={s - p} y1={p} x2={s - p} y2={s - p} stroke="currentColor" strokeWidth={1.5} />
          <rect x={s - p - 2 - s * 0.6} y={p + 1} width={s * 0.6} height={3} rx={1} fill="currentColor" />
          <rect x={s - p - 2 - s * 0.4} y={m - 1} width={s * 0.4} height={3} rx={1} fill="currentColor" />
          <rect x={s - p - 2 - s * 0.7} y={s - p - 4} width={s * 0.7} height={3} rx={1} fill="currentColor" />
        </svg>
      );
    case "vtop":
      return (
        <svg width={s} height={s} viewBox={`0 0 ${s} ${s}`}>
          <line x1={p} y1={p} x2={s - p} y2={p} stroke="currentColor" strokeWidth={1.5} />
          <rect x={p + 1} y={p + 2} width={4} height={s * 0.5} rx={1} fill="currentColor" />
          <rect x={m + 1} y={p + 2} width={4} height={s * 0.35} rx={1} fill="currentColor" />
        </svg>
      );
    case "vmiddle":
      return (
        <svg width={s} height={s} viewBox={`0 0 ${s} ${s}`}>
          <line x1={p} y1={m} x2={s - p} y2={m} stroke="currentColor" strokeWidth={1} strokeDasharray="2 2" />
          <rect x={p + 1} y={m - s * 0.25} width={4} height={s * 0.5} rx={1} fill="currentColor" />
          <rect x={m + 1} y={m - s * 0.175} width={4} height={s * 0.35} rx={1} fill="currentColor" />
        </svg>
      );
    case "vbottom":
      return (
        <svg width={s} height={s} viewBox={`0 0 ${s} ${s}`}>
          <line x1={p} y1={s - p} x2={s - p} y2={s - p} stroke="currentColor" strokeWidth={1.5} />
          <rect x={p + 1} y={s - p - 2 - s * 0.5} width={4} height={s * 0.5} rx={1} fill="currentColor" />
          <rect x={m + 1} y={s - p - 2 - s * 0.35} width={4} height={s * 0.35} rx={1} fill="currentColor" />
        </svg>
      );
    default:
      return null;
  }
}

// ── Props ───────────────────────────────────────────────────
interface PieMenuProps {
  state: PieMenuState;
  items: PieMenuItem[];
  angleOffset: number;
  rootMenu: PieMenuItem[] | null;
  breadcrumb: string;
  onDrillDown: (index: number) => void;
  onDrillUp: () => void;
  onDispatch: (action: NonNullable<PieMenuItem["action"]>) => void;
  onClose: () => void;
}

// ── Component ───────────────────────────────────────────────
export default function PieMenu({
  state,
  items,
  angleOffset,
  rootMenu,
  breadcrumb,
  onDrillDown,
  onDrillUp,
  onDispatch,
  onClose,
}: PieMenuProps) {
  const { t } = useLocale();

  const segments = useMemo(
    () => (items.length > 0 ? getSegmentAngles(items.length, angleOffset) : []),
    [items, angleOffset],
  );

  // Hovered index from mouse position
  const hoveredIndex = items.length > 0
    ? hitTest(state.mouseAngle, state.mouseR, items, angleOffset)
    : -1;

  const handleClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    e.preventDefault();

    if (hoveredIndex === -2) {
      // Deadzone → drill up
      onDrillUp();
      return;
    }
    if (hoveredIndex === -3 || hoveredIndex === -1) {
      // Far away or no segment → close
      onClose();
      return;
    }

    const item = items[hoveredIndex];
    if (!item) return;

    if (item.children && item.children.length > 0) {
      onDrillDown(hoveredIndex);
    } else if (item.action) {
      onDispatch(item.action);
      onClose();
    }
  };

  const noSelection = !rootMenu;

  return (
    <div
      style={{
        position: "fixed",
        inset: 0,
        zIndex: 2000,
        pointerEvents: "none",
      }}
    >
      <div
        style={{
          position: "absolute",
          left: state.position.x - HALF,
          top: state.position.y - HALF,
          width: SVG_SIZE,
          height: SVG_SIZE,
          pointerEvents: "auto",
          cursor: "default",
        }}
        onClick={handleClick}
        onContextMenu={(e) => { e.preventDefault(); onClose(); }}
      >
        <svg
          width={SVG_SIZE}
          height={SVG_SIZE}
          viewBox={`0 0 ${SVG_SIZE} ${SVG_SIZE}`}
          style={{
            overflow: "visible",
            opacity: state.isFading ? 0 : 1,
            transition: `opacity ${140}ms ease`,
          }}
        >
          {/* Filters */}
          <defs>
            <filter id="pie-glow" x="-50%" y="-50%" width="200%" height="200%">
              <feGaussianBlur stdDeviation="4" result="blur" />
              <feMerge>
                <feMergeNode in="blur" />
                <feMergeNode in="SourceGraphic" />
              </feMerge>
            </filter>
          </defs>

          {noSelection ? (
            /* Empty state */
            <>
              <circle cx={HALF} cy={HALF} r={RING_OUTER} fill="#ffffff08" stroke="#ffffff15" strokeWidth={1} />
              <text
                x={HALF}
                y={HALF}
                textAnchor="middle"
                dominantBaseline="central"
                fill="#ffffff55"
                fontSize={13}
                fontFamily="system-ui, sans-serif"
              >
                {t("pieNoSelection" as TranslationKey)}
              </text>
            </>
          ) : (
            <>
              {/* Segments */}
              {segments.map((seg, i) => {
                const item = items[i];
                const isHovered = hoveredIndex === i;
                const fillColor = isHovered ? `${item.color}30` : "#ffffff05";
                const strokeColor = isHovered ? `${item.color}55` : "#ffffff08";

                return (
                  <path
                    key={item.id}
                    d={describeDonutSegment(HALF, HALF, RING_INNER, RING_OUTER, seg.start, seg.end)}
                    fill={fillColor}
                    stroke={strokeColor}
                    strokeWidth={1}
                    style={{ transition: "fill 100ms ease, stroke 100ms ease" }}
                  />
                );
              })}

              {/* Cursor indicator arc */}
              {state.mouseR >= RING_INNER && hoveredIndex >= 0 && (
                <path
                  d={describeDonutSegment(
                    HALF, HALF,
                    RING_OUTER - 2, RING_OUTER + 4,
                    state.mouseAngle - INDICATOR_WIDTH_DEG / 2,
                    state.mouseAngle + INDICATOR_WIDTH_DEG / 2,
                  )}
                  fill={items[hoveredIndex]?.color ?? "#8b5cf6"}
                  filter="url(#pie-glow)"
                  opacity={0.9}
                />
              )}

              {/* Labels */}
              {segments.map((seg, i) => {
                const item = items[i];
                const isHovered = hoveredIndex === i;
                const labelX = HALF + LABEL_R * Math.cos(deg2rad(seg.center));
                const labelY = HALF + LABEL_R * Math.sin(deg2rad(seg.center));

                const displayLabel = t(item.labelKey as TranslationKey);
                const icon = item.icon ?? "";

                // Determine label content
                let labelContent: React.ReactNode;
                if (item.alignType) {
                  labelContent = (
                    <foreignObject
                      x={labelX - 10}
                      y={labelY - 10}
                      width={20}
                      height={20}
                      style={{ color: isHovered ? "#fff" : "#ffffff88" }}
                    >
                      <div style={{ display: "flex", alignItems: "center", justifyContent: "center", width: "100%", height: "100%" }}>
                        <AlignIcon type={item.alignType} size={16} />
                      </div>
                    </foreignObject>
                  );
                } else {
                  labelContent = null;
                }

                const textFill = isHovered ? "#fff" : "#ffffff88";
                const bgFill = "#0e0e1cdd";
                const fs = item.fontSize ?? 11;
                const textWidth = (icon ? icon.length * fs + 4 : 0) + displayLabel.length * fs * 0.6 + 16;
                const textHeight = fs + 10;

                return (
                  <g
                    key={item.id}
                    className="pie-menu-label-group"
                    style={{
                      animation: `piePopIn ${POP_IN_MS}ms ease-out ${i * STAGGER_MS}ms both`,
                    }}
                  >
                    {item.alignType ? (
                      labelContent
                    ) : (
                      <>
                        {/* Background rect */}
                        <rect
                          x={labelX - textWidth / 2}
                          y={labelY - textHeight / 2}
                          width={textWidth}
                          height={textHeight}
                          rx={4}
                          fill={bgFill}
                          stroke={isHovered ? `${item.color}55` : "transparent"}
                          strokeWidth={1}
                        />
                        {/* Color dot for color items */}
                        {item.isColor || item.action ? (
                          <circle
                            cx={labelX - textWidth / 2 + 10}
                            cy={labelY}
                            r={4}
                            fill={item.color}
                          />
                        ) : null}
                        {/* Text */}
                        <text
                          x={labelX}
                          y={labelY}
                          textAnchor="middle"
                          dominantBaseline="central"
                          fill={textFill}
                          fontSize={fs}
                          fontFamily="system-ui, sans-serif"
                          style={{
                            ...item.labelStyle,
                            transition: "fill 100ms ease",
                            transform: isHovered ? "scale(1.08)" : undefined,
                            transformOrigin: `${labelX}px ${labelY}px`,
                          }}
                        >
                          {icon ? `${icon} ` : ""}{displayLabel}
                        </text>
                      </>
                    )}
                  </g>
                );
              })}

              {/* Center deadzone */}
              <circle
                cx={HALF}
                cy={HALF}
                r={DEADZONE}
                fill="#0e0e1ccc"
                stroke="#ffffff15"
                strokeWidth={1}
              />
              {/* Breadcrumb text */}
              {breadcrumb ? (
                <text
                  x={HALF}
                  y={HALF}
                  textAnchor="middle"
                  dominantBaseline="central"
                  fill="#ffffffaa"
                  fontSize={9}
                  fontFamily="system-ui, sans-serif"
                >
                  {breadcrumb.length > 12 ? "‹" : breadcrumb || "‹"}
                </text>
              ) : (
                <text
                  x={HALF}
                  y={HALF}
                  textAnchor="middle"
                  dominantBaseline="central"
                  fill="#ffffff55"
                  fontSize={10}
                  fontFamily="system-ui, sans-serif"
                >
                  ●
                </text>
              )}
            </>
          )}
        </svg>
      </div>
    </div>
  );
}

"use client";

import React, { useMemo } from "react";
import { useLocale } from "@/lib/i18n/useLocale";
import type { TranslationKey } from "@/lib/i18n/locales";
import {
  type PieMenuState,
  DEADZONE,
  RING_INNER,
  RING_OUTER,
  LABEL_R,
  GAP_DEG,
  FADE_MS,
  getSegmentAngles,
} from "@/hooks/usePieMenu";
import type { PieMenuItem } from "@/lib/pieMenuData";

// ── Constants ───────────────────────────────────────────────
const CLOSE_R = LABEL_R + 60;
const INDICATOR_WIDTH_DEG = 6;
const STAGGER_MS = 18;
const POP_IN_MS = 140;
const SVG_SIZE = (CLOSE_R + 20) * 2;
const HALF = SVG_SIZE / 2;

// ── Geometry helpers ────────────────────────────────────────
const deg2rad = (d: number) => (d * Math.PI) / 180;

function describeDonutSegment(
  cx: number, cy: number,
  innerR: number, outerR: number,
  startDeg: number, endDeg: number,
): string {
  const s1 = deg2rad(startDeg);
  const e1 = deg2rad(endDeg);
  const sweep = endDeg - startDeg;
  const large = sweep > 180 ? 1 : 0;

  const ox1 = cx + outerR * Math.cos(s1);
  const oy1 = cy + outerR * Math.sin(s1);
  const ox2 = cx + outerR * Math.cos(e1);
  const oy2 = cy + outerR * Math.sin(e1);
  const ix1 = cx + innerR * Math.cos(e1);
  const iy1 = cy + innerR * Math.sin(e1);
  const ix2 = cx + innerR * Math.cos(s1);
  const iy2 = cy + innerR * Math.sin(s1);

  return [
    `M ${ox1} ${oy1}`,
    `A ${outerR} ${outerR} 0 ${large} 1 ${ox2} ${oy2}`,
    `L ${ix1} ${iy1}`,
    `A ${innerR} ${innerR} 0 ${large} 0 ${ix2} ${iy2}`,
    "Z",
  ].join(" ");
}

function hitTest(angle: number, r: number, items: PieMenuItem[], angleOffset: number): number {
  if (r < DEADZONE) return -2; // deadzone
  if (r > CLOSE_R) return -3;  // far away
  if (items.length === 0) return -1;

  const angles = getSegmentAngles(items.length, angleOffset);
  for (let i = 0; i < angles.length; i++) {
    let { start, end } = angles[i];
    // Normalize to 0-360
    start = ((start % 360) + 360) % 360;
    end = ((end % 360) + 360) % 360;

    let inRange: boolean;
    if (start <= end) {
      inRange = angle >= start && angle <= end;
    } else {
      // Wraps around 0°
      inRange = angle >= start || angle <= end;
    }
    if (inRange && r >= RING_INNER - 10 && r <= CLOSE_R) return i;
  }
  return -1;
}

// ── AlignIcon SVG helper ────────────────────────────────────
function AlignIcon({ type, size = 16 }: { type: string; size?: number }) {
  const s = size;
  const m = s / 2;
  const p = 2;

  switch (type) {
    case "hleft":
      return (
        <svg width={s} height={s} viewBox={`0 0 ${s} ${s}`}>
          <line x1={p} y1={p} x2={p} y2={s - p} stroke="currentColor" strokeWidth={1.5} />
          <rect x={p + 2} y={p + 1} width={s * 0.6} height={3} rx={1} fill="currentColor" />
          <rect x={p + 2} y={m - 1} width={s * 0.4} height={3} rx={1} fill="currentColor" />
          <rect x={p + 2} y={s - p - 4} width={s * 0.7} height={3} rx={1} fill="currentColor" />
        </svg>
      );
    case "hcenter":
      return (
        <svg width={s} height={s} viewBox={`0 0 ${s} ${s}`}>
          <line x1={m} y1={p} x2={m} y2={s - p} stroke="currentColor" strokeWidth={1} strokeDasharray="2 2" />
          <rect x={m - s * 0.3} y={p + 1} width={s * 0.6} height={3} rx={1} fill="currentColor" />
          <rect x={m - s * 0.2} y={m - 1} width={s * 0.4} height={3} rx={1} fill="currentColor" />
          <rect x={m - s * 0.35} y={s - p - 4} width={s * 0.7} height={3} rx={1} fill="currentColor" />
        </svg>
      );
    case "hright":
      return (
        <svg width={s} height={s} viewBox={`0 0 ${s} ${s}`}>
          <line x1={s - p} y1={p} x2={s - p} y2={s - p} stroke="currentColor" strokeWidth={1.5} />
          <rect x={s - p - 2 - s * 0.6} y={p + 1} width={s * 0.6} height={3} rx={1} fill="currentColor" />
          <rect x={s - p - 2 - s * 0.4} y={m - 1} width={s * 0.4} height={3} rx={1} fill="currentColor" />
          <rect x={s - p - 2 - s * 0.7} y={s - p - 4} width={s * 0.7} height={3} rx={1} fill="currentColor" />
        </svg>
      );
    case "vtop":
      return (
        <svg width={s} height={s} viewBox={`0 0 ${s} ${s}`}>
          <line x1={p} y1={p} x2={s - p} y2={p} stroke="currentColor" strokeWidth={1.5} />
          <rect x={p + 1} y={p + 2} width={4} height={s * 0.5} rx={1} fill="currentColor" />
          <rect x={m + 1} y={p + 2} width={4} height={s * 0.35} rx={1} fill="currentColor" />
        </svg>
      );
    case "vmiddle":
      return (
        <svg width={s} height={s} viewBox={`0 0 ${s} ${s}`}>
          <line x1={p} y1={m} x2={s - p} y2={m} stroke="currentColor" strokeWidth={1} strokeDasharray="2 2" />
          <rect x={p + 1} y={m - s * 0.25} width={4} height={s * 0.5} rx={1} fill="currentColor" />
          <rect x={m + 1} y={m - s * 0.175} width={4} height={s * 0.35} rx={1} fill="currentColor" />
        </svg>
      );
    case "vbottom":
      return (
        <svg width={s} height={s} viewBox={`0 0 ${s} ${s}`}>
          <line x1={p} y1={s - p} x2={s - p} y2={s - p} stroke="currentColor" strokeWidth={1.5} />
          <rect x={p + 1} y={s - p - 2 - s * 0.5} width={4} height={s * 0.5} rx={1} fill="currentColor" />
          <rect x={m + 1} y={s - p - 2 - s * 0.35} width={4} height={s * 0.35} rx={1} fill="currentColor" />
        </svg>
      );
    default:
      return null;
  }
}

// ── Props ───────────────────────────────────────────────────
interface PieMenuProps {
  state: PieMenuState;
  items: PieMenuItem[];
  angleOffset: number;
  rootMenu: PieMenuItem[] | null;
  breadcrumb: string;
  onDrillDown: (index: number) => void;
  onDrillUp: () => void;
  onDispatch: (action: NonNullable<PieMenuItem["action"]>) => void;
  onClose: () => void;
}

// ── Component ───────────────────────────────────────────────
export default function PieMenu({
  state,
  items,
  angleOffset,
  rootMenu,
  breadcrumb,
  onDrillDown,
  onDrillUp,
  onDispatch,
  onClose,
}: PieMenuProps) {
  const { t } = useLocale();

  const segments = useMemo(
    () => (items.length > 0 ? getSegmentAngles(items.length, angleOffset) : []),
    [items, angleOffset],
  );

  // Hovered index from mouse position
  const hoveredIndex = items.length > 0
    ? hitTest(state.mouseAngle, state.mouseR, items, angleOffset)
    : -1;

  const handleClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    e.preventDefault();

    if (hoveredIndex === -2) {
      // Deadzone → drill up
      onDrillUp();
      return;
    }
    if (hoveredIndex === -3 || hoveredIndex === -1) {
      // Far away or no segment → close
      onClose();
      return;
    }

    const item = items[hoveredIndex];
    if (!item) return;

    if (item.children && item.children.length > 0) {
      onDrillDown(hoveredIndex);
    } else if (item.action) {
      onDispatch(item.action);
      onClose();
    }
  };

  const noSelection = !rootMenu;

  return (
    <div
      style={{
        position: "fixed",
        inset: 0,
        zIndex: 2000,
        pointerEvents: "none",
      }}
    >
      <div
        style={{
          position: "absolute",
          left: state.position.x - HALF,
          top: state.position.y - HALF,
          width: SVG_SIZE,
          height: SVG_SIZE,
          pointerEvents: "auto",
          cursor: "default",
        }}
        onClick={handleClick}
        onContextMenu={(e) => { e.preventDefault(); onClose(); }}
      >
        <svg
          width={SVG_SIZE}
          height={SVG_SIZE}
          viewBox={`0 0 ${SVG_SIZE} ${SVG_SIZE}`}
          style={{
            overflow: "visible",
            opacity: state.isFading ? 0 : 1,
            transition: `opacity ${140}ms ease`,
          }}
        >
          {/* Filters */}
          <defs>
            <filter id="pie-menu-glow" x="-50%" y="-50%" width="200%" height="200%">
              <feGaussianBlur stdDeviation="4" result="blur" />
              <feMerge>
                <feMergeNode in="blur" />
                <feMergeNode in="SourceGraphic" />
              </feMerge>
            </filter>
          </defs>

          {noSelection ? (
            /* Empty state */
            <>
              <circle cx={HALF} cy={HALF} r={RING_OUTER} fill="#ffffff08" stroke="#ffffff15" strokeWidth={1} />
              <text
                x={HALF}
                y={HALF}
                textAnchor="middle"
                dominantBaseline="central"
                fill="#ffffff55"
                fontSize={13}
                fontFamily="system-ui, sans-serif"
              >
                {t("pieNoSelection" as TranslationKey)}
              </text>
            </>
          ) : (
            <>
              {/* Segments */}
              {segments.map((seg, i) => {
                const item = items[i];
                const isHovered = hoveredIndex === i;
                const fillColor = isHovered ? `${item.color}30` : "#ffffff05";
                const strokeColor = isHovered ? `${item.color}55` : "#ffffff08";

                return (
                  <path
                    key={item.id}
                    d={describeDonutSegment(HALF, HALF, RING_INNER, RING_OUTER, seg.start, seg.end)}
                    fill={fillColor}
                    stroke={strokeColor}
                    strokeWidth={1}
                    style={{ transition: "fill 100ms ease, stroke 100ms ease" }}
                  />
                );
              })}

              {/* Cursor indicator arc */}
              {state.mouseR >= RING_INNER && hoveredIndex >= 0 && (
                <path
                  d={describeDonutSegment(
                    HALF, HALF,
                    RING_OUTER - 2, RING_OUTER + 4,
                    state.mouseAngle - INDICATOR_WIDTH_DEG / 2,
                    state.mouseAngle + INDICATOR_WIDTH_DEG / 2,
                  )}
                  fill={items[hoveredIndex]?.color ?? "#8b5cf6"}
                  filter="url(#pie-glow)"
                  opacity={0.9}
                />
              )}

              {/* Labels */}
              {segments.map((seg, i) => {
                const item = items[i];
                const isHovered = hoveredIndex === i;
                const labelX = HALF + LABEL_R * Math.cos(deg2rad(seg.center));
                const labelY = HALF + LABEL_R * Math.sin(deg2rad(seg.center));

                const displayLabel = t(item.labelKey as TranslationKey);
                const icon = item.icon ?? "";

                // Determine label content
                let labelContent: React.ReactNode;
                if (item.alignType) {
                  labelContent = (
                    <foreignObject
                      x={labelX - 10}
                      y={labelY - 10}
                      width={20}
                      height={20}
                      style={{ color: isHovered ? "#fff" : "#ffffff88" }}
                    >
                      <div style={{ display: "flex", alignItems: "center", justifyContent: "center", width: "100%", height: "100%" }}>
                        <AlignIcon type={item.alignType} size={16} />
                      </div>
                    </foreignObject>
                  );
                } else {
                  labelContent = null;
                }

                const textFill = isHovered ? "#fff" : "#ffffff88";
                const bgFill = "#0e0e1cdd";
                const fs = item.fontSize ?? 11;
                const textWidth = (icon ? icon.length * fs + 4 : 0) + displayLabel.length * fs * 0.6 + 16;
                const textHeight = fs + 10;

                return (
                  <g
                    key={item.id}
                    className="pie-menu-label-group"
                    style={{
                      animation: `piePopIn ${POP_IN_MS}ms ease-out ${i * STAGGER_MS}ms both`,
                    }}
                  >
                    {item.alignType ? (
                      labelContent
                    ) : (
                      <>
                        {/* Background rect */}
                        <rect
                          x={labelX - textWidth / 2}
                          y={labelY - textHeight / 2}
                          width={textWidth}
                          height={textHeight}
                          rx={4}
                          fill={bgFill}
                          stroke={isHovered ? `${item.color}55` : "transparent"}
                          strokeWidth={1}
                        />
                        {/* Color dot for color items */}
                        {item.isColor || item.action ? (
                          <circle
                            cx={labelX - textWidth / 2 + 10}
                            cy={labelY}
                            r={4}
                            fill={item.color}
                          />
                        ) : null}
                        {/* Text */}
                        <text
                          x={labelX}
                          y={labelY}
                          textAnchor="middle"
                          dominantBaseline="central"
                          fill={textFill}
                          fontSize={fs}
                          fontFamily="system-ui, sans-serif"
                          style={{
                            ...item.labelStyle,
                            transition: "fill 100ms ease",
                            transform: isHovered ? "scale(1.08)" : undefined,
                            transformOrigin: `${labelX}px ${labelY}px`,
                          }}
                        >
                          {icon ? `${icon} ` : ""}{displayLabel}
                        </text>
                      </>
                    )}
                  </g>
                );
              })}

              {/* Center deadzone */}
              <circle
                cx={HALF}
                cy={HALF}
                r={DEADZONE}
                fill="#0e0e1ccc"
                stroke="#ffffff15"
                strokeWidth={1}
              />
              {/* Breadcrumb text */}
              {breadcrumb ? (
                <text
                  x={HALF}
                  y={HALF}
                  textAnchor="middle"
                  dominantBaseline="central"
                  fill="#ffffffaa"
                  fontSize={9}
                  fontFamily="system-ui, sans-serif"
                >
                  {breadcrumb.length > 12 ? "‹" : breadcrumb || "‹"}
                </text>
              ) : (
                <text
                  x={HALF}
                  y={HALF}
                  textAnchor="middle"
                  dominantBaseline="central"
                  fill="#ffffff55"
                  fontSize={10}
                  fontFamily="system-ui, sans-serif"
                >
                  ●
                </text>
              )}
            </>
          )}
        </svg>
      </div>
    </div>
  );
}

"use client";

import React, { useMemo } from "react";
import { useLocale } from "@/lib/i18n/useLocale";
import type { TranslationKey } from "@/lib/i18n/locales";
import {
  type PieMenuState,
  DEADZONE,
  RING_INNER,
  RING_OUTER,
  LABEL_R,
  GAP_DEG,
  FADE_MS,
  getSegmentAngles,
} from "@/hooks/usePieMenu";
import type { PieMenuItem } from "@/lib/pieMenuData";

// ── Constants ───────────────────────────────────────────────
const CLOSE_R = LABEL_R + 60;
const INDICATOR_WIDTH_DEG = 6;
const STAGGER_MS = 18;
const POP_IN_MS = 140;
const SVG_SIZE = (CLOSE_R + 20) * 2;
const HALF = SVG_SIZE / 2;

// ── Geometry helpers ────────────────────────────────────────
const deg2rad = (d: number) => (d * Math.PI) / 180;

function describeDonutSegment(
  cx: number, cy: number,
  innerR: number, outerR: number,
  startDeg: number, endDeg: number,
): string {
  const s1 = deg2rad(startDeg);
  const e1 = deg2rad(endDeg);
  const sweep = endDeg - startDeg;
  const large = sweep > 180 ? 1 : 0;

  const ox1 = cx + outerR * Math.cos(s1);
  const oy1 = cy + outerR * Math.sin(s1);
  const ox2 = cx + outerR * Math.cos(e1);
  const oy2 = cy + outerR * Math.sin(e1);
  const ix1 = cx + innerR * Math.cos(e1);
  const iy1 = cy + innerR * Math.sin(e1);
  const ix2 = cx + innerR * Math.cos(s1);
  const iy2 = cy + innerR * Math.sin(s1);

  return [
    `M ${ox1} ${oy1}`,
    `A ${outerR} ${outerR} 0 ${large} 1 ${ox2} ${oy2}`,
    `L ${ix1} ${iy1}`,
    `A ${innerR} ${innerR} 0 ${large} 0 ${ix2} ${iy2}`,
    "Z",
  ].join(" ");
}

function hitTest(angle: number, r: number, items: PieMenuItem[], angleOffset: number): number {
  if (r < DEADZONE) return -2; // deadzone
  if (r > CLOSE_R) return -3;  // far away
  if (items.length === 0) return -1;

  const angles = getSegmentAngles(items.length, angleOffset);
  for (let i = 0; i < angles.length; i++) {
    let { start, end } = angles[i];
    // Normalize to 0-360
    start = ((start % 360) + 360) % 360;
    end = ((end % 360) + 360) % 360;

    let inRange: boolean;
    if (start <= end) {
      inRange = angle >= start && angle <= end;
    } else {
      // Wraps around 0°
      inRange = angle >= start || angle <= end;
    }
    if (inRange && r >= RING_INNER - 10 && r <= CLOSE_R) return i;
  }
  return -1;
}

// ── AlignIcon SVG helper ────────────────────────────────────
function AlignIcon({ type, size = 16 }: { type: string; size?: number }) {
  const s = size;
