import { useState, useRef, useCallback, useEffect } from "react";
import { useFlowStore } from "@/store/useFlowStore";
import { NODE_MENU, EDGE_MENU, BOTH_MENU, type PieMenuItem, type PieMenuAction } from "@/lib/pieMenuData";
import type { TranslationKey } from "@/lib/i18n/locales";

export interface PieMenuState {
  isOpen: boolean;
  position: { x: number; y: number };
  path: number[];
  hoveredIndex: number;
  isFading: boolean;
  mouseAngle: number;
  mouseR: number;
}

const INITIAL_STATE: PieMenuState = {
  isOpen: false,
  position: { x: 0, y: 0 },
  path: [],
  hoveredIndex: -1,
  isFading: false,
  mouseAngle: 0,
  mouseR: 0,
};

// ── Layout constants ────────────────────────────────────────
export const DEADZONE = 28;
export const RING_INNER = 48;
export const RING_OUTER = 88;
export const LABEL_R = 128;
export const GAP_DEG = 1.2;
export const FADE_MS = 140;
const CLOSE_R = LABEL_R + 60;

// ── Selectors (stable references) ───────────────────────────
const selectSelectedNodeIds = (s: { nodes: { id: string; selected?: boolean }[] }) =>
  s.nodes.filter((n) => n.selected).map((n) => n.id).join(",");
const selectSelectedEdgeIds = (s: { edges: { id: string; selected?: boolean; data?: { isBridgeEdge?: boolean } }[] }) =>
  s.edges.filter((e) => e.selected && !e.data?.isBridgeEdge).map((e) => e.id).join(",");

// ── Geometry helpers ────────────────────────────────────────
export function getSegmentAngles(count: number, angleOffset = 0) {
  const sliceDeg = 360 / count;
  return Array.from({ length: count }, (_, i) => {
    const center = angleOffset + i * sliceDeg;
    const half = sliceDeg / 2 - GAP_DEG / 2;
    return { start: center - half, center, end: center + half };
  });
}

export function resolveCurrentMenu(root: PieMenuItem[], path: number[]): PieMenuItem[] {
  let items = root;
  for (const idx of path) {
    const child = items[idx]?.children;
    if (!child) return items;
    items = child;
  }
  return items;
}

function resolveAngleOffset(root: PieMenuItem[], path: number[]): number {
  let items = root;
  let offset = 0;
  for (const idx of path) {
    const item = items[idx];
    if (!item?.children) break;
    if (item.angleOffset !== undefined) offset = item.angleOffset;
    else offset = 0;
    items = item.children;
  }
  // Check if the current level's parent had angleOffset
  return offset;
}

function getBreadcrumb(root: PieMenuItem[], path: number[], t: (k: TranslationKey) => string): string {
  const parts: string[] = [];
  let items = root;
  for (const idx of path) {
    const item = items[idx];
    if (!item) break;
    const icon = item.icon ?? "";
    const label = t(item.labelKey as TranslationKey);
    parts.push(`${icon} ${label}`.trim());
    if (!item.children) break;
    items = item.children;
  }
  return parts.join(" › ");
}

// ── Hook ────────────────────────────────────────────────────
export function usePieMenu() {
  const [state, setState] = useState<PieMenuState>(INITIAL_STATE);
  const mousePosRef = useRef({ x: 0, y: 0 });
  const fadeTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const stateRef = useRef(state);
  stateRef.current = state;

  const selectedNodeIdStr = useFlowStore(selectSelectedNodeIds);
  const selectedEdgeIdStr = useFlowStore(selectSelectedEdgeIds);

  const selectedNodeIds = selectedNodeIdStr ? selectedNodeIdStr.split(",") : [];
  const selectedEdgeIds = selectedEdgeIdStr ? selectedEdgeIdStr.split(",") : [];

  // Determine root menu
  const hasNodes = selectedNodeIds.length > 0;
  const hasEdges = selectedEdgeIds.length > 0;
  const rootMenu: PieMenuItem[] | null = hasNodes && hasEdges ? BOTH_MENU
    : hasNodes ? NODE_MENU
    : hasEdges ? EDGE_MENU
    : null;

  const currentItems = rootMenu ? resolveCurrentMenu(rootMenu, state.path) : [];
  const currentAngleOffset = rootMenu ? resolveAngleOffset(rootMenu, state.path) : 0;

  const clearFadeTimer = useCallback(() => {
    if (fadeTimerRef.current !== null) {
      clearTimeout(fadeTimerRef.current);
      fadeTimerRef.current = null;
    }
  }, []);

  const close = useCallback(() => {
    clearFadeTimer();
    setState(INITIAL_STATE);
  }, [clearFadeTimer]);

  const open = useCallback(() => {
    clearFadeTimer();
    setState({
      ...INITIAL_STATE,
      isOpen: true,
      position: { ...mousePosRef.current },
    });
  }, [clearFadeTimer]);

  const drillDown = useCallback((index: number) => {
    clearFadeTimer();
    setState((s) => ({ ...s, isFading: true, hoveredIndex: -1 }));
    fadeTimerRef.current = setTimeout(() => {
      fadeTimerRef.current = null;
      setState((s) => ({ ...s, isFading: false, path: [...s.path, index] }));
    }, FADE_MS);
  }, [clearFadeTimer]);

  const drillUp = useCallback(() => {
    const s = stateRef.current;
    if (s.path.length === 0) {
      close();
      return;
    }
    clearFadeTimer();
    setState((prev) => ({ ...prev, isFading: true, hoveredIndex: -1 }));
    fadeTimerRef.current = setTimeout(() => {
      fadeTimerRef.current = null;
      setState((prev) => ({ ...prev, isFading: false, path: prev.path.slice(0, -1) }));
    }, FADE_MS);
  }, [close, clearFadeTimer]);

  const dispatchAction = useCallback((action: PieMenuAction) => {
    const store = useFlowStore.getState();
    const nodeIds = store.nodes.filter((n) => n.selected).map((n) => n.id);
    const edgeIds = store.edges.filter((e) => e.selected && !e.data?.isBridgeEdge).map((e) => e.id);
    // Pre-build lookup map for toggle actions (avoid O(N) find per node)
    const nodeMap = new Map(store.nodes.map((n) => [n.id, n]));

    switch (action.type) {
      case "nodeFillColor":
        nodeIds.forEach((id) => store.updateNodeColors(id, action.color || null, undefined));
        break;
      case "nodeBorderColor":
        nodeIds.forEach((id) => store.updateNodeColors(id, undefined, action.color || null));
        break;
      case "nodeTextColor":
        nodeIds.forEach((id) => store.updateNodeTextStyle(id, { textColor: action.color }));
        break;
      case "nodeBorderWidth":
        nodeIds.forEach((id) => store.updateNodeBorder(id, action.width, undefined));
        break;
      case "nodeBorderStyle":
        nodeIds.forEach((id) => store.updateNodeBorder(id, undefined, action.style));
        break;
      case "nodeOrder":
        store.reorderNodes(nodeIds, action.order);
        break;
      case "nodeAlign":
        store.alignNodes(nodeIds, action.alignment);
        break;
      case "nodeDistribute":
        store.distributeNodes(nodeIds, action.axis);
        break;
      case "nodeFontSize":
        nodeIds.forEach((id) => store.updateNodeTextStyle(id, { fontSize: action.size }));
        break;
      case "nodeBold":
        nodeIds.forEach((id) => {
          const node = nodeMap.get(id);
          store.updateNodeTextStyle(id, { bold: !node?.data?.bold });
        });
        break;
      case "nodeItalic":
        nodeIds.forEach((id) => {
          const node = nodeMap.get(id);
          store.updateNodeTextStyle(id, { italic: !node?.data?.italic });
        });
        break;
      case "nodeUnderline":
        nodeIds.forEach((id) => {
          const node = nodeMap.get(id);
          store.updateNodeTextStyle(id, { underline: !node?.data?.underline });
        });
        break;
      case "nodeTextAlign":
        nodeIds.forEach((id) => store.updateNodeTextStyle(id, { textAlign: action.align }));
        break;
      case "nodeTextVerticalAlign":
        nodeIds.forEach((id) => store.updateNodeTextStyle(id, { textVerticalAlign: action.align }));
        break;
      case "edgeLineType":
        edgeIds.forEach((id) => store.updateEdgeType(id, action.edgeType));
        break;
      case "edgeMarkerEnd":
        edgeIds.forEach((id) => store.updateEdgeMarkers(id, undefined, action.marker));
        break;
      case "edgeMarkerStart":
        edgeIds.forEach((id) => store.updateEdgeMarkers(id, action.marker, undefined));
        break;
      case "edgeStrokeWidth":
        edgeIds.forEach((id) => store.updateEdgeStyle(id, action.width, undefined));
        break;
      case "edgeStrokeStyle":
        edgeIds.forEach((id) => store.updateEdgeStyle(id, undefined, undefined, action.style));
        break;
      case "edgeColor":
        edgeIds.forEach((id) => store.updateEdgeStyle(id, undefined, action.color));
        break;
    }
  }, []);

  // ── Event listeners ─────────────────────────────────────
  useEffect(() => {
    const onMouseMove = (e: MouseEvent) => {
      mousePosRef.current = { x: e.clientX, y: e.clientY };
      const s = stateRef.current;
      if (!s.isOpen) return;

      const dx = e.clientX - s.position.x;
      const dy = e.clientY - s.position.y;
      const r = Math.sqrt(dx * dx + dy * dy);
      const angle = ((Math.atan2(dy, dx) * 180) / Math.PI + 360) % 360;

      setState((prev) => ({ ...prev, mouseAngle: angle, mouseR: r }));
    };

    const onKeyDown = (e: KeyboardEvent) => {
      if (e.repeat) return;
      const tag = (e.target as HTMLElement)?.tagName;
      if (tag === "INPUT" || tag === "TEXTAREA") return;
      // Also skip if contentEditable
      if ((e.target as HTMLElement)?.isContentEditable) return;

      if (e.key === "r" || e.key === "R") {
        if (e.ctrlKey || e.metaKey || e.altKey) return;
        e.preventDefault();
        const s = stateRef.current;
        if (s.isOpen) {
          setState(INITIAL_STATE);
        } else {
          setState({
            ...INITIAL_STATE,
            isOpen: true,
            position: { ...mousePosRef.current },
          });
        }
      }
    };

    const onContextMenu = (e: MouseEvent) => {
      if (stateRef.current.isOpen) {
        e.preventDefault();
        setState(INITIAL_STATE);
      }
    };

    window.addEventListener("mousemove", onMouseMove);
    window.addEventListener("keydown", onKeyDown);
    window.addEventListener("contextmenu", onContextMenu, true);

    return () => {
      window.removeEventListener("mousemove", onMouseMove);
      window.removeEventListener("keydown", onKeyDown);
      window.removeEventListener("contextmenu", onContextMenu, true);
    };
  }, []);

  return {
    state,
    setState,
    rootMenu,
    currentItems,
    currentAngleOffset,
    selectedNodeIds,
    selectedEdgeIds,
    open,
    close,
    drillDown,
    drillUp,
    dispatchAction,
    getBreadcrumb: (t: (k: TranslationKey) => string) => rootMenu ? getBreadcrumb(rootMenu, state.path, t) : "",
  };
}
